CREATE OR REPLACE PROCEDURE PROC_EMP_SAL(
  P_EMP_ID IN EMP.emp_id%TYPE,
  P_SAL OUT EMP.salary%TYPE
) IS
BEGIN
  SELECT salary INTO P_SAL
  FROM EMP
  WHERE emp_id = P_EMP_ID;
END;

